// hooks/useFoodPolling.js
import { useEffect, useRef } from 'react';
import { useDispatch } from 'react-redux';
import { applyPollUpdate } from './redux_utils/foodSlice';

function useFoodPolling(interval = 120000) {
  const dispatch = useDispatch();
  const timerRef = useRef(null);

  useEffect(() => {

    const poll = async () => {
      try {
        const res = await fetch(`http://localhost:3009`);
        if (!res.ok) return;
        const data = await res.json();
        if (data.success) {
          dispatch(applyPollUpdate(data));
          console.log(data);
        }
      } catch (err) {
        console.error('[useFoodPolling] fetch failed:', err);
      }
    };

    poll();
    timerRef.current = setInterval(poll, interval);

    return () => clearInterval(timerRef.current);
  }, [interval, dispatch]);
}

